#include "interface.h"
#include <yyjson.h>

uint64_t compute_checksum(const std::string& json_input) {
    yyjson_doc *doc = yyjson_read(json_input.c_str(), json_input.size(), 0);
    if (!doc) return 0; // fallback (should not occur with valid input)
    yyjson_val *root = yyjson_doc_get_root(doc);
    uint64_t sum = 0;
    if (yyjson_is_arr(root)) {
        yyjson_arr_iter iter;
        yyjson_arr_iter_init(root, &iter);
        yyjson_val *val;
        while ((val = yyjson_arr_iter_next(&iter))) {
            if (!yyjson_is_obj(val)) continue;
            yyjson_val *id_val = yyjson_obj_get(val, "id");
            if (id_val) sum += yyjson_get_uint(id_val);
            yyjson_val *nested_val = yyjson_obj_get(val, "nested");
            if (nested_val && yyjson_is_obj(nested_val)) {
                yyjson_val *a_val = yyjson_obj_get(nested_val, "a");
                if (a_val) sum += yyjson_get_uint(a_val);
                yyjson_val *b_val = yyjson_obj_get(nested_val, "b");
                if (b_val) sum += yyjson_get_uint(b_val);
            }
        }
    }
    yyjson_doc_free(doc);
    return sum;
}
